<template>
  <div id="admin">
    <nav class="navbar navbar-dark fixed-top flex-md-nowrap p-0 shadow">
      <span class="navbar-brand col-sm-3 col-md-2 mr-0">矿业大学ATM系统</span>
      <span class="nav_title">{{userInfo.idcard || userInfo.name}}{{userInfo.userType == 1? '用户': '管理员'}}，欢迎来到矿业大学ATM系统</span>
      <ul class="navbar-nav px-3">
        <li class="nav-item text-nowrap">
          <a>
              <img width="50" style="border-radius: 5px;" :src="logo" class="navbar-brand-imgmx-auto" alt="...">
            </a>
        </li>
        <li class="nav-item text-nowrap">
          <a class="nav-link" @click="logout">退出登录</a>
        </li>
      </ul>
    </nav>

    <div class="container-fluid" style="height: 100vh">
      <div class="row">
        <nav class="col-md-2 d-none d-md-block bg-light sidebar">
          <div class="sidebar-sticky" style="margin-top: 40px;">
            <el-menu
              :default-active="defaultActive"
              class="el-menu-vertical-demo">

              <!-- 用户菜单 -->
              <el-menu-item index="enquiry" @click="goTo('/admin/enquiry')" v-if="userInfo.userType == 1">
                <i class="el-icon-document-copy"></i>
                <span slot="title">明细查询</span>
              </el-menu-item>
              <el-menu-item index="recharge" @click="goTo('/admin/recharge')" v-if="userInfo.userType == 1">
                <i class="el-icon-document-copy"></i>
                <span slot="title">存款</span>
              </el-menu-item>
              <el-menu-item index="withdrawals" @click="goTo('/admin/withdrawals')" v-if="userInfo.userType == 1">
                <i class="el-icon-document-copy"></i>
                <span slot="title">取款</span>
              </el-menu-item>
              <el-menu-item index="transfer" @click="goTo('/admin/transfer')" v-if="userInfo.userType == 1">
                <i class="el-icon-document-copy"></i>
                <span slot="title">转账</span>
              </el-menu-item>
              <el-menu-item index="changePassword" @click="goTo('/admin/changePassword')" v-if="userInfo.userType == 1">
                <i class="el-icon-document-copy"></i>
                <span slot="title">修改密码</span>
              </el-menu-item>
              <el-menu-item index="userCharts" @click="goTo('/admin/userCharts')" v-if="userInfo.userType == 1">
                <i class="el-icon-document-copy"></i>
                <span slot="title">数据统计</span>
              </el-menu-item>

              <!-- 管理员菜单 -->
              <el-menu-item index="adminRecharge" @click="goTo('/admin/adminRecharge')" v-if="userInfo.userType == 2">
                <i class="el-icon-document-copy"></i>
                <span slot="title">加钞/取钞</span>
              </el-menu-item>
              <el-menu-item index="atmAccount" @click="goTo('/admin/atmAccount')" v-if="userInfo.userType == 2">
                <i class="el-icon-document-copy"></i>
                <span slot="title">钞票记录</span>
              </el-menu-item>
              <el-menu-item index="adminTrad" @click="goTo('/admin/adminTrad')" v-if="userInfo.userType == 2">
                <i class="el-icon-document-copy"></i>
                <span slot="title">明细查询</span>
              </el-menu-item>
              <el-menu-item index="adminUser" @click="goTo('/admin/adminUser')" v-if="userInfo.userType == 2">
                <i class="el-icon-document-copy"></i>
                <span slot="title">用户查询</span>
              </el-menu-item>
              <el-menu-item index="adminCharts" @click="goTo('/admin/adminCharts')" v-if="userInfo.userType == 2">
                <i class="el-icon-document-copy"></i>
                <span slot="title">数据统计</span>
              </el-menu-item>

            
              
            </el-menu>
          </div>
        </nav>
       <main role="main" class="col-md-9 ml-sm-auto col-lg-10 px-4">
         <router-view></router-view>
       </main>
      </div>
    </div>
  </div>
</template>

<script>
  import {mapState} from 'vuex';
  import {mapActions} from 'vuex'
  import { MessageBox } from 'element-ui';

  export default {
    data(){
      return {
        userInfo: {
          user: {},
        }, // 个人信息
        defaultActive: 'wanted', // 默认激活的菜单
        logo: require("@/assets/logo.png"), // logo图片
      }
    },
    mounted(){
       let result = window.localStorage.getItem("token");
        if(!result){
          MessageBox({
            type: 'info',
            message: "您还没登录",
			      showClose: true,
          });
          this.$router.push('/login');
        }
        
        this.defaultActive = window.location.hash.split('/')[window.location.hash.split('/').length - 1]
        this.userInfo = JSON.parse(window.localStorage.getItem('userInfo'))

        this.$bus.$on("userInfoChange", this.userInfoChange); 


    },
    methods:{
      // 用户信息变化
      userInfoChange(){
        console.log('用户信息变化');
        this.userInfo = JSON.parse(window.localStorage.getItem('userInfo'))
      },
      logout(){
        this.$confirm('您确定退出登录吗?', '提示', {
          confirmButtonText: '确定',
          cancelButtonText: '取消',
          type: 'warning'
        }).then(async () => {
          this.$router.push('/login');
        }).catch(() => {
          this.$message({
            type: 'info',
            message: '已取消退出'
          });
        });
      },
      goTo(path){
        this.$router.push(path);
      },
    },
    beforeDestroy() {
      this.$bus.$off("userInfoChange"); // 解绑全局事件总线事件
    }
  }
</script>

<style>
.two-line {
    overflow: hidden; 
    display: -webkit-box; 
    -webkit-box-orient: vertical;
    -webkit-line-clamp: 2;
    text-overflow: ellipsis; 
}
</style>

<style scoped>

#admin {
  background-color: skyblue;
  background-image: url(../AdminLogin/images/bg.jpg);
}

.navbar {
  font-family: cursive;
  font-size: 1.5rem;
  background-color: darkgray;
}

.navbar-brand {
  font-size: 1.5rem!important;
}

.nav_title {
  color: white!important;
}

.bd-placeholder-img {
  font-size: 1.125rem;
  text-anchor: middle;
  -webkit-user-select: none;
  -moz-user-select: none;
  -ms-user-select: none;
  user-select: none;
}

@media (min-width: 768px) {
  .bd-placeholder-img-lg {
    font-size: 3.5rem;
  }
}
#me {
  font-size: .875rem;
}

.feather {
  width: 16px;
  height: 16px;
  vertical-align: text-bottom;
}

/*
 * Sidebar
 */

.sidebar {
  position: fixed;
  top: 0;
  bottom: 0;
  left: 0;
  z-index: 100; /* Behind the navbar */
  padding: 48px 0 0; /* Height of navbar */
  box-shadow: inset -1px 0 0 rgba(0, 0, 0, .1);
}

.sidebar-sticky {
  position: relative;
  top: 0;
  height: calc(100vh - 48px);
  padding-top: .5rem;
  overflow-x: hidden;
  overflow-y: auto; /* Scrollable contents if viewport is shorter than content. */
}

@supports ((position: -webkit-sticky) or (position: sticky)) {
  .sidebar-sticky {
    position: -webkit-sticky;
    position: sticky;
  }
}

.sidebar .nav-link {
  font-weight: 500;
  color: #333;
}
.sidebar-sticky .navbar-brand {
    display: block;
    text-align: center;
    padding-top: 1.25rem;
    padding-bottom: 1.25rem;
    color: #12263f;
    margin-right: 0;
    font-size: 1.0625rem;
    line-height: inherit;
    white-space: nowrap;
    background: #f8f9fa;
}
.navbar-brand img{
  -radius: 10px;
}
.sidebar .nav-link .feather {
  margin-right: 4px;
  color: #999;
}

.sidebar .nav-link.active {
  color: #007bff;
}

.sidebar .nav-link:hover .feather,
.sidebar .nav-link.active .feather {
  color: inherit;
}

.sidebar-heading {
  font-size: .75rem;
  text-transform: uppercase;
}

/*
 * Content
 */

[role="main"] {
  padding-top: 133px; /* Space for fixed navbar */
}

@media (min-width: 768px) {
  [role="main"] {
    padding-top: 67px; /* Space for fixed navbar */
  }
}

/*
 * Navbar
 */
.nav_title{
  color: white;
}
.navbar-brand {
  padding-top: .75rem;
  padding-bottom: .75rem;
  font-size: 1rem;
  background-color: rgba(0, 0, 0, .25);
  box-shadow: inset -1px 0 0 rgba(0, 0, 0, .25);
}

.navbar-nav{
  flex-direction: row !important;
}
.navbar-nav>.nav-item{
  margin-left: 40px;
  cursor: pointer;
}

</style>



